                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is MobileClientException.PairingFailed -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is MobileClientException.PairingTransportUnavailable -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
        }
    }

    override fun write(value: MobileClientException, buf: ByteBuffer) {
        when(value) {
            is MobileClientException.InvalidIdentity -> {
                buf.putInt(1)
                Unit
            }
            is MobileClientException.InvalidConfiguration -> {
                buf.putInt(2)
                Unit
            }
            is MobileClientException.InvalidRecord -> {
                buf.putInt(3)
                Unit
            }
            is MobileClientException.AlreadyOpened -> {
